#!/usr/bin/env node
// Cross-reference JSX class usage vs Tailwind compiled CSS output.
// Catches dead classes (used in JSX, not generated by Tailwind).
//
// Three classes of false positive have bitten this script before; each
// addressed below in the parser functions:
// 1. JSX template literals: only string-literal fragments are class names,
//    not variable refs, operators, or JSX fragments.
// 2. cn() calls: extract literals from inside argument lists.
// 3. CSS escapes: \. in selector means literal `.` in class name, not regex
//    end. Use a `\\.|[^...\\]` pattern that consumes escapes correctly.
//
// Usage: pnpm audit:tailwind
// Requires: dev server running at :1420 (cargo tauri dev).

import fs from 'node:fs';
import path from 'node:path';
import http from 'node:http';

const SRC = path.resolve('src');
const DEV_URL = 'http://localhost:1420/src/styles/globals.css';

function walk(dir, out = []) {
  for (const e of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, e.name);
    if (e.isDirectory()) walk(p, out);
    else if (/\.(tsx|ts)$/.test(e.name)) out.push(p);
  }
  return out;
}

// Tailwind class names are all lowercase, may contain - _ : / [ ] ( ) % digits.
// Never contain uppercase letters (camelCase vars), . (member access), or
// JS/JSX syntax (< > ? { } = , ;).
function isLikelyClass(token) {
  if (!token) return false;
  if (/[A-Z]/.test(token)) return false;
  if (/[<>{}?;,=]/.test(token)) return false;
  if (token.includes('.') && !token.includes('[')) return false;
  return true;
}

// Recursively pull class names from a template-literal body. Strips ${...}
// expressions at the top level, but RECURSES into each expression to find
// string literals — without that, `cn(`base ${cond ? 'a' : 'b'}`)` would
// drop the conditional class names.
function extractFromTemplate(literal) {
  const out = [];
  let i = 0;
  let buf = '';
  while (i < literal.length) {
    if (literal[i] === '$' && literal[i + 1] === '{') {
      // flush buffer
      for (const c of buf.split(/\s+/)) if (c) out.push(c);
      buf = '';
      i += 2;
      // find matching }
      let depth = 1;
      const exprStart = i;
      while (i < literal.length && depth > 0) {
        if (literal[i] === '{') depth++;
        else if (literal[i] === '}') depth--;
        if (depth > 0) i++;
      }
      const expr = literal.slice(exprStart, i);
      // extract any nested literals inside the expression
      for (const m of expr.matchAll(/'([^']*)'|"([^"]*)"|`([^`]*)`/g)) {
        const s = m[1] ?? m[2] ?? m[3] ?? '';
        for (const c of extractFromTemplate(s)) out.push(c);
      }
      i++; // skip }
    } else {
      buf += literal[i];
      i++;
    }
  }
  for (const c of buf.split(/\s+/)) if (c) out.push(c);
  return out;
}

function extractFromCnCall(args) {
  const out = [];
  for (const m of args.matchAll(/'([^']*)'|"([^"]*)"|`([^`]*)`/g)) {
    const s = m[1] ?? m[2] ?? m[3] ?? '';
    for (const c of extractFromTemplate(s)) out.push(c);
  }
  return out;
}

function extractUsedClasses(files) {
  const used = new Set();
  for (const f of files) {
    const src = fs.readFileSync(f, 'utf8');
    // className="static classes"
    for (const m of src.matchAll(/className="([^"]+)"/g)) {
      for (const c of m[1].split(/\s+/)) if (c) used.add(c);
    }
    // className={`template ${expr}`}
    for (const m of src.matchAll(/className=\{`([^`]+)`\}/g)) {
      for (const c of extractFromTemplate(m[1])) used.add(c);
    }
    // cn('a', cond && 'b', `c ${expr}`)
    for (const m of src.matchAll(/cn\(([\s\S]*?)\)/g)) {
      for (const c of extractFromCnCall(m[1])) used.add(c);
    }
  }
  return used;
}

// CSS class selector: a `.` at a selector position (preceded by `{`, `}`,
// `,`, `;`, `>`, `+`, `~`, whitespace, or start of input — never inside a
// value like `font-size: 0.875rem`). The body may contain escaped chars
// (e.g. \. for literal `.`, \: for literal `:`), stopping at un-escaped
// `:` (pseudo-class boundary), `{`, `,`, or whitespace.
function extractDefinedClasses(css) {
  const defined = new Set();
  const re = /(?<=[{};,>+~\s]|^)\.((?:\\.|[^:{,\s\\])+)/g;
  for (const m of css.matchAll(re)) {
    defined.add(m[1].replace(/\\(.)/g, '$1'));
  }
  return defined;
}

async function fetchCSS() {
  return new Promise((resolve, reject) => {
    const req = http.get(DEV_URL, res => {
      if (res.statusCode !== 200) {
        return reject(new Error(`HTTP ${res.statusCode}`));
      }
      let b = '';
      res.on('data', c => b += c);
      res.on('end', () => {
        // Vite wraps the compiled CSS as a JS string literal in a module:
        //   const __vite__css = "...escaped CSS...";
        // The bytes we receive are JS source, so `\\` in the response is a
        // single backslash in the actual CSS. Extract and unescape.
        const m = b.match(/const __vite__css = "([\s\S]*?)"\n/);
        if (!m) {
          // Fallback: response is already raw CSS (some Vite versions).
          resolve(b);
          return;
        }
        const unescaped = m[1]
          .replace(/\\n/g, '\n')
          .replace(/\\t/g, '\t')
          .replace(/\\"/g, '"')
          .replace(/\\\\/g, '\\');
        resolve(unescaped);
      });
      res.on('error', reject);
    });
    req.on('error', reject);
    req.setTimeout(3000, () => req.destroy(new Error('timeout 3s')));
  });
}

async function main() {
  const files = walk(SRC);
  const rawUsed = extractUsedClasses(files);
  const used = new Set([...rawUsed].filter(isLikelyClass));
  const dropped = rawUsed.size - used.size;

  let css;
  try {
    css = await fetchCSS();
  } catch (e) {
    console.error(`Cannot fetch ${DEV_URL}: ${e.message}`);
    console.error('Start dev server first: cd .. && cargo tauri dev');
    process.exit(2);
  }

  const defined = extractDefinedClasses(css);

  const missing = [];
  for (const c of used) {
    if (c.includes('[')) continue; // arbitrary value classes — regex can't reliably verify
    const candidates = [c];
    const stripped = c.replace(
      /^(hover|focus|focus-visible|disabled|active|group|group-hover|dark|md|sm|lg|xl|2xl|first|last|odd|even|placeholder|peer|peer-checked|data-\[[^\]]+\])\:/,
      ''
    );
    if (stripped !== c) candidates.push(stripped);
    if (!candidates.some(x => defined.has(x))) missing.push(c);
  }

  if (missing.length === 0) {
    console.log(`OK: ${used.size} classes used, ${defined.size} defined, 0 missing.`);
    if (dropped > 0) console.log(`(dropped ${dropped} non-class tokens: JSX vars, expressions)`);
    process.exit(0);
  }

  console.error(`FAIL: ${missing.length} classes used in JSX but not found in compiled CSS:`);
  for (const c of missing) console.error('  ' + c);
  if (dropped > 0) console.error(`(dropped ${dropped} non-class tokens)`);
  process.exit(1);
}

main().catch(e => { console.error(e); process.exit(1); });
